using System.Collections;
using UnityEngine;
using UnityEngine.InputSystem;

/// <summary>
/// Tarefa #29 — vibração do comando (gamepad rumble) para feedback de
/// combate: aplica motores baixo/alto (Gamepad.SetMotorSpeeds) durante
/// "duration" segundos e repõe a 0 no fim. Respeita
/// <see cref="GameSettings.VibrationEnabled"/> — se desligado (ou alterado
/// para desligado a meio de um pulso), os motores são imediatamente postos a
/// 0 e nenhum pulso novo é iniciado.
///
/// Segue o mesmo padrão de singleton de AudioManager/GameSettings (Instance,
/// DontDestroyOnLoad, EnsureExists/isAutoFallback).
/// </summary>
public class RumbleManager : MonoBehaviour
{
    public static RumbleManager Instance { get; private set; }

    private Coroutine _pulseRoutine;

    /// <summary>
    /// Marca instâncias criadas automaticamente por <see cref="EnsureExists"/>
    /// antes da primeira cena carregar (ver PlayerProgress.cs para a explicação
    /// completa — Tarefa #15 "GameBootstrap e singletons").
    /// </summary>
    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(RumbleManager) + " (Fallback)");
        var instance = go.AddComponent<RumbleManager>();
        instance.isAutoFallback = true;
    }

    private void OnEnable()
    {
        if (GameSettings.Instance != null) GameSettings.Instance.SettingsChanged += HandleSettingsChanged;
    }

    private void OnDisable()
    {
        if (GameSettings.Instance != null) GameSettings.Instance.SettingsChanged -= HandleSettingsChanged;
        StopRumble();
    }

    /// <summary>
    /// Aplica um pulso de vibração no gamepad activo (motores baixo/alto,
    /// 0-1) durante "duration" segundos. Sem efeito se a vibração estiver
    /// desligada nas Opções (GameSettings.VibrationEnabled) ou se não houver
    /// gamepad ligado. Um novo pulso substitui o anterior.
    /// </summary>
    public void Pulse(float lowFrequency, float highFrequency, float duration)
    {
        if (GameSettings.Instance != null && !GameSettings.Instance.VibrationEnabled) return;

        var gamepad = Gamepad.current;
        if (gamepad == null) return;

        if (_pulseRoutine != null) StopCoroutine(_pulseRoutine);

        gamepad.SetMotorSpeeds(Mathf.Clamp01(lowFrequency), Mathf.Clamp01(highFrequency));
        _pulseRoutine = StartCoroutine(StopAfter(duration));
    }

    private IEnumerator StopAfter(float duration)
    {
        yield return new WaitForSeconds(duration);
        StopMotors();
        _pulseRoutine = null;
    }

    private void HandleSettingsChanged()
    {
        if (GameSettings.Instance != null && !GameSettings.Instance.VibrationEnabled) StopRumble();
    }

    private void StopRumble()
    {
        if (_pulseRoutine != null)
        {
            StopCoroutine(_pulseRoutine);
            _pulseRoutine = null;
        }

        StopMotors();
    }

    private void StopMotors()
    {
        Gamepad.current?.SetMotorSpeeds(0f, 0f);
    }
}
